INSERT INTO teacher_profiles (user_id, bio, instruments, specialties, avatar_url, available_for_new_students, lesson_durations)
VALUES
  ('c1000000-0000-0000-0000-000000000208', '{"he":"מנכ״לית אקדמא ומנהלת מחלקת הפסנתר. פסנתרנית ומורה בכירה.","en":"Director of the Academy and Head of the Piano Department. Pianist and senior teacher.","ar":"مديرة الأكاديمية ورئيسة قسم البيانو. عازفة بيانو ومعلمة كبيرة.","ru":"Директор академии и заведующая отделением фортепиано. Пианистка и старший преподаватель."}'::jsonb, ARRAY["פסנתר"]::TEXT[], ARRAY[]::TEXT[], NULL, TRUE, ARRAY[30,45,60]),
  ('c1000000-0000-0000-0000-000000000209', '{"he":"מנהל מחלקת כלי קשת בקונסרבטוריון אקדמא.","en":"Head of the String Instruments Department at the Academy Conservatory.","ar":"رئيس قسم الآلات الوترية في معهد الأكاديمية الموسيقي.","ru":"Заведующий отделением струнных инструментов в консерватории академии."}'::jsonb, ARRAY["כלי קשת"]::TEXT[], ARRAY[]::TEXT[], NULL, TRUE, ARRAY[30,45,60]),
  ('c1000000-0000-0000-0000-000000000210', '{"he":"מנהל מחלקת כלי נשיפה והקשה ומנהל פרויקטים.","en":"Head of the Wind and Percussion Instruments Department and Project Manager.","ar":"رئيس قسم آلات النفخ والإيقاع ومدير المشاريع.","ru":"Заведующий отделением духовых и ударных инструментов и руководитель проектов."}'::jsonb, ARRAY["כלי נשיפה והקשה"]::TEXT[], ARRAY[]::TEXT[], NULL, TRUE, ARRAY[30,45,60]),
  ('c1000000-0000-0000-0000-000000000211', '{"he":"מנהל מחלקת כלי פריטה (גיטרה וכלים דומים). מוזיקאי פעיל.","en":"Head of the Plucked Instruments Department (Guitar and Similar Instruments). Active musician.","ar":"رئيس قسم الآلات المنقوسة (الجيتار والآلات المشابهة). موسيقار نشط.","ru":"Заведующий отделением щипковых инструментов (гитара и подобные). Активный музыкант."}'::jsonb, ARRAY["גיטרה","כלי פריטה"]::TEXT[], ARRAY[]::TEXT[], NULL, TRUE, ARRAY[30,45,60]),
  ('c1000000-0000-0000-0000-000000000212', '{"he":"מנהלת המחלקה הווקאלית בקונסרבטוריון.","en":"Head of the Vocal Department at the Conservatory.","ar":"رئيسة القسم الصوتي في المعهد الموسيقي.","ru":"Заведующая вокальным отделением консерватории."}'::jsonb, ARRAY["פיתוח קול"]::TEXT[], ARRAY[]::TEXT[], NULL, TRUE, ARRAY[30,45,60]),
  ('c1000000-0000-0000-0000-000000000213', '{"he":"מנהל המחלקה למוסיקה רב תחומית.","en":"Head of the Interdisciplinary Music Department.","ar":"رئيس قسم الموسيقى متعددة التخصصات.","ru":"Заведующий отделением междисциплинарной музыки."}'::jsonb, ARRAY["ג'אז","פופ","רוק"]::TEXT[], ARRAY[]::TEXT[], NULL, TRUE, ARRAY[30,45,60]),
  ('c1000000-0000-0000-0000-000000000214', '{"he":"מנהלת מחלקת תאוריה ותורת המוסיקה.","en":"Head of the Theory and Music Theory Department.","ar":"رئيسة قسم النظرية وتاريخ الموسيقى.","ru":"Заведующая отделением теории и истории музыки."}'::jsonb, ARRAY["תאוריה","תורת המוסיקה"]::TEXT[], ARRAY[]::TEXT[], NULL, TRUE, ARRAY[30,45,60]),
  ('c1000000-0000-0000-0000-000000000215', '{"he":"מלחין הבית של הקונסרבטוריון.","en":"House Composer of the Conservatory.","ar":"الموسيقار المقيم في المعهد الموسيقي.","ru":"Композитор при консерватории."}'::jsonb, ARRAY["הלחנה"]::TEXT[], ARRAY[]::TEXT[], NULL, TRUE, ARRAY[30,45,60]),
  ('c1000000-0000-0000-0000-000000000216', '{"he":"אחראית על לימודי טרום כלי לילדים בגיל הרך.","en":"Responsible for Pre-Instrumental Studies for Young Children.","ar":"مسؤولة عن دراسات ما قبل الآلات الموسيقية للأطفال الصغار.","ru":"Ответственная за допрофессиональное обучение детей раннего возраста."}'::jsonb, ARRAY["הגיל הרך"]::TEXT[], ARRAY[]::TEXT[], NULL, TRUE, ARRAY[30,45,60]),
  ('c1000000-0000-0000-0000-000000000217', '{"he":"מנהלנית הקונסרבטוריון.","en":"Administrator of the Conservatory.","ar":"مسؤولة إدارة المعهد الموسيقي.","ru":"Администратор консерватории."}'::jsonb, ARRAY["מנהלה"]::TEXT[], ARRAY[]::TEXT[], NULL, TRUE, ARRAY[30,45,60]),
  ('c1000000-0000-0000-0000-000000000218', '{"he":"מזכירה בצוות אקדמא.","en":"Secretary at the Academy Staff.","ar":"سكرتيرة في فريق الأكاديمية.","ru":"Секретарь в аппарате академии."}'::jsonb, ARRAY["מזכירות"]::TEXT[], ARRAY[]::TEXT[], NULL, TRUE, ARRAY[30,45,60]),
