  ('c1000000-0000-0000-0000-000000000282', '{"he":"מורה לפסנתר וליווי פסנתר.","en":"Teacher of piano and piano accompaniment.","ar":"معلمة البيانو والمرافقة الموسيقية على البيانو.","ru":"Преподаватель фортепиано и аккомпанемента на фортепиано."}'::jsonb, ARRAY["פסנתר","ליווי פסנתר"]::TEXT[], ARRAY[]::TEXT[], NULL, TRUE, ARRAY[30,45,60]),
