  ARRAY['IN_APP', 'EMAIL'],
  '2026-03-05 08:00:00+00'
WHERE NOT EXISTS (SELECT 1 FROM announcements WHERE id = 'a0000000-0000-0000-0000-000000000002'::uuid);

SELECT
